@use '../../../styles' as *;

.nav {
  position: sticky;
  top: 0;
  z-index: var(--portfolio-z-sticky);
  background-color: var(--portfolio-surface-terra-subtle);
  box-shadow: 0 4px 12px -4px rgba(0, 0, 0, 0.05);

  &::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    height: 10px;
    transform: translateY(100%);
    backdrop-filter: blur(3px);
    -webkit-backdrop-filter: blur(3px);
    mask-image: linear-gradient(to bottom, rgba(0, 0, 0, 0.2), transparent);
    -webkit-mask-image: linear-gradient(to bottom, rgba(0, 0, 0, 0.2), transparent);
    pointer-events: none;
  }
}

.navInner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  max-width: $elan-container-wide;
  margin: 0 auto;
  padding: var(--portfolio-spacer-1-5x) var(--portfolio-spacer-2x);

  @media #{$elan-mq-sm} {
    padding: var(--portfolio-spacer-1-5x) var(--portfolio-spacer-4x);
  }
}

.logo {
  display: inline-flex;
  align-items: center;
  gap: $portfolio-spacer-0-5x;
  text-decoration: none;
  // ─── Identity priority (AP-066) ──────────────────────────────────────────
  // The logo/name is a non-negotiable. It must never wrap or collapse under
  // flex pressure at any viewport width. Three properties work in concert:
  //
  //   flex-shrink: 0     — stops the flex algorithm from assigning this item
  //                        less than its intrinsic width
  //   white-space: nowrap — closes the inline formatting context at the anchor
  //                        level so the browser never considers a line-break
  //                        within the logo group (nowrap on .logoText alone is
  //                        insufficient — the anchor can still receive a
  //                        compressed flex base size that triggers wrapping)
  //   min-width: max-content — sets an absolute floor equal to the widest
  //                        single-line measurement; the flex algorithm cannot
  //                        allocate less even in hypothetical size calculations
  //
  // The tagline (.links > .tagline) is the designated soft edge: it absorbs
  // all viewport squeeze by wrapping to a maximum of 2 lines. The logo
  // never yields.
  flex-shrink: 0;
  white-space: nowrap;
  min-width: max-content;
  @include transition-fast;

  &:hover {
    .logoMark {
      background-color: var(--portfolio-text-neutral-max);
    }

    .logoText {
      color: var(--portfolio-text-neutral-max);
    }
  }
}

.logoMark {
  display: inline-block;
  height: calc($portfolio-type-2xl * 1.2);
  aspect-ratio: 1;
  flex-shrink: 0;
  background-color: $portfolio-accent-60;
  mask-image: url('/images/yg-logo.svg');
  mask-size: contain;
  mask-repeat: no-repeat;
  @include transition-fast;
}

.logoText {
  font-family: $portfolio-font-serif;
  font-size: $portfolio-type-2xl;
  font-weight: $portfolio-weight-regular;
  line-height: $portfolio-leading-snug;
  color: $portfolio-accent-60;
  letter-spacing: $portfolio-tracking-tight;
  white-space: nowrap; // belt-and-suspenders; primary guard is on .logo
  @include transition-fast;
}

.links {
  display: flex;
  align-items: center;
  gap: var(--portfolio-spacer-3x);
  // min-width: 0 allows flex children (notably .tagline) to shrink below their
  // intrinsic content width so they wrap instead of pushing the logo.
  min-width: 0;
}

.link {
  font-family: var(--portfolio-font-sans);
  font-size: var(--portfolio-type-sm);
  font-weight: var(--portfolio-weight-regular);
  color: var(--portfolio-text-secondary);
  text-decoration: none;
  @include transition-fast;

  &:hover {
    color: var(--portfolio-text-primary);
  }
}

.linkActive {
  color: var(--portfolio-text-primary);
  font-weight: var(--portfolio-weight-medium);
}

.tagline {
  @include body-sm;
  color: var(--portfolio-text-secondary);
  // The tagline is the designated soft edge of the nav: it yields to narrow
  // viewports by wrapping to a maximum of 2 lines. It never compromises the
  // logo — the logo always wins. See .logo above and AP-066.
  min-width: 0;
  text-align: right;
  display: -webkit-box;
  -webkit-box-orient: vertical;
  -webkit-line-clamp: 2;
  line-clamp: 2;
  overflow: hidden;
}
